Below is a step-by-step guide and a complete example in Swift that shows how to implement a simple Tic-Tac-Toe game in a single ViewController using UIKit.

1. Set Up Storyboard:
- Drag 9 UIButtons in a 3x3 grid
- Drag 1 Reset UIButton
- (Optional) UILabel for status
- Assign tags 0–8 to buttons

2. Create Outlets and Actions:
- Create IBOutlet collection: tileButtons
- Create IBAction for tileTapped
- Create IBAction for resetGame

3. Full Swift Code:

import UIKit

class ViewController: UIViewController {

    @IBOutlet var tileButtons: [UIButton]!
    @IBOutlet weak var statusLabel: UILabel!

    var board = [Int](repeating: 0, count: 9)
    var currentPlayer = 1

    let winningCombinations = [
        [0,1,2],[3,4,5],[6,7,8],
        [0,3,6],[1,4,7],[2,5,8],
        [0,4,8],[2,4,6]
    ]

    override func viewDidLoad() {
        super.viewDidLoad()
        statusLabel.text = "X's turn"
    }

    @IBAction func tileTapped(_ sender: UIButton) {
        let tag = sender.tag

        if board[tag] == 0 {
            board[tag] = currentPlayer

            if currentPlayer == 1 {
                sender.setTitle("X", for: .normal)
                currentPlayer = 2
                statusLabel.text = "O's turn"
            } else {
                sender.setTitle("O", for: .normal)
                currentPlayer = 1
                statusLabel.text = "X's turn"
            }

            checkForWinner()
        }
    }

    func checkForWinner() {
        for combo in winningCombinations {
            let a = board[combo[0]]
            let b = board[combo[1]]
            let c = board[combo[2]]

            if a != 0 && a == b && b == c {
                statusLabel.text = (a == 1) ? "X wins!" : "O wins!"

                for button in tileButtons {
                    button.isEnabled = false
                }
                return
            }
        }

        if !board.contains(0) {
            statusLabel.text = "It's a draw!"
        }
    }

    @IBAction func resetGame(_ sender: UIButton) {
        board = [Int](repeating: 0, count: 9)
        currentPlayer = 1

        for button in tileButtons {
            button.isEnabled = true
            button.setTitle("", for: .normal)
        }

        statusLabel.text = "X's turn"
    }
}
